// Helper: retrieve expansion content for a lesson by ID.
export function getDGRInfohasExpansion(lessonId: string): any[] {
  return dgrInfohasExpansion[lessonId] || [];
}

// Helper: count of lessons with expansion content.
export function getDGRInfohasExpansionCount(): number {
  return Object.keys(dgrInfohasExpansion).length;
}

// Helper: list of lesson IDs with expansion content.
export function getDGRInfohasExpansionLessonIds(): string[] {
  return Object.keys(dgrInfohasExpansion);
}

// Helper: approximate total word count of expansion content (for QA reporting).
export function getDGRInfohasExpansionWordCount(): number {
  let total = 0;
  for (const blocks of Object.values(dgrInfohasExpansion)) {
    for (const block of blocks) {
      if (typeof block.text === "string") total += block.text.split(/\s+/).length;
      if (Array.isArray(block.items)) total += block.items.join(" ").split(/\s+/).length;
      if (Array.isArray(block.rows)) {
        for (const row of block.rows) {
          if (Array.isArray(row)) total += row.join(" ").split(/\s+/).length;
        }
      }
    }
  }
  return total;
}
